// Preparar cenas para geração via Veo 3 Flash
const data = $input.first().json.scriptData || $input.first().json;
const cenas = data.cenas || data.script?.cenas || [];

const tempDir = `${process.env.TEMP_DIR || '/data/temp'}/${data.videoId}`;

const fs = require('fs');
fs.mkdirSync(tempDir, { recursive: true });

// Sufixo visual obrigatório em todos os prompts
const VISUAL_SUFFIX = ', divine golden light breaking through clouds, heavenly atmosphere, ancient Judea first century AD, cinematic composition, photorealistic, ultra detailed, no text overlay, no watermark, no modern elements, no anachronisms';

return cenas.map((cena, i) => ({
  json: {
    videoId: data.videoId,
    cenaNumero: cena.numero || (i + 1),
    duracaoSegundos: Math.min(Math.max(cena.duracao_segundos || 6, 5), 8),
    prompt: cena.prompt_imagem + VISUAL_SUFFIX,
    tempDir,
    outputFile: `${tempDir}/scene_${String(i + 1).padStart(2, '0')}.mp4`
  }
}));

// Combinar binary do Veo3 com metadados da cena atual
const sceneData = $('Process Each Scene').first().json;
const binaryData = $input.first().binary;

if (!binaryData || !binaryData.data) {
  throw new Error(`Veo 3 não retornou vídeo binário para cena ${sceneData.cenaNumero}. Resposta: ${JSON.stringify($input.first().json)}`);
}

return [{
  json: {
    videoId: sceneData.videoId,
    cenaNumero: sceneData.cenaNumero,
    outputFile: sceneData.outputFile,
    tempDir: sceneData.tempDir,
    duracaoSegundos: sceneData.duracaoSegundos
  },
  binary: binaryData
}];

const cmdOut = $input.first().json.stdout || '';
const match = cmdOut.match(/PROCESSED:(.+)/);

if (!match) {
  const stderr = $input.first().json.stderr || '';
  throw new Error(`FFmpeg falhou para cena ${$('Merge Scene Data').first().json.cenaNumero}: ${stderr}`);
}

const sceneData = $('Merge Scene Data').first().json;

return [{
  json: {
    videoId: sceneData.videoId,
    cenaNumero: sceneData.cenaNumero,
    outputFile: match[1].trim(),
    status: 'scene_ready'
  }
}];

// Todas as cenas prontas — montar resumo
const allScenes = $('Confirm Scene Ready').all();
const videoId = allScenes[0]?.json?.videoId;

return [{
  json: {
    videoId,
    totalScenes: allScenes.length,
    scenes: allScenes.map(s => ({
      numero: s.json.cenaNumero,
      file: s.json.outputFile,
      status: s.json.status
    })),
    status: 'all_scenes_ready'
  }
}];
